CREATE OR REPLACE FUNCTION fn_total_pendiente_estadia(p_estadia_id INT)
RETURNS DECIMAL(12,2)
LANGUAGE plpgsql
AS $$
DECLARE
    v_total_hospedaje DECIMAL(12,2);
    v_total_consumos DECIMAL(12,2);
    v_total_pagado DECIMAL(12,2);
    v_pendiente DECIMAL(12,2);
BEGIN
    SELECT COALESCE(total_hospedaje, 0) INTO v_total_hospedaje
    FROM estadias WHERE id = p_estadia_id;

    SELECT COALESCE(SUM(subtotal), 0) INTO v_total_consumos
    FROM consumos WHERE estadia_id = p_estadia_id;

    SELECT COALESCE(SUM(monto), 0) INTO v_total_pagado
    FROM pagos WHERE estadia_id = p_estadia_id;

    v_pendiente := (v_total_hospedaje + v_total_consumos) - v_total_pagado;

    RETURN v_pendiente;
END;
$$;
